 59	function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
 60	  switch (harness) {
 61	    case "claude-code":
 62	      return "claude";
 63	    case "codex":
 64	      return "codex";
 65	    case "copilot":
 66	      return "copilot";
