230	  if (execution.exitCode !== 0) {
231	    return {
232	      outcome: "blocked",
233	      errors: [
234	        executionFailureError({
235	          provider: context.provider,
236	          stderr: execution.stderr,
237	          errorCode: execution.errorCode,
238	        }),
239	      ],
240	      warnings: [],
241	    };
242	  }
243	
244	  if (execution.parseError || !execution.parsedResult) {
245	    return {
