248	        blockedError(
249	          "PROVIDER_OUTPUT_INVALID",
250	          `Provider output was invalid for ${context.provider}.`,
251	          execution.parseError
252	        ),
253	      ],
254	      warnings: [],
255	    };
256	  }
257	
258	  const result = buildCleanupResult({
259	    cleanupBatchPath: context.cleanupBatchPath,
260	    payload: execution.parsedResult,
