452	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
453	  return z
454	    .object({
455	      command: z.string().min(1),
456	      version: z.literal(1),
457	      status: cliStatusSchema,
458	      outcome: z.string().min(1),
459	      result: resultSchema.optional(),
460	      errors: z.array(cliErrorSchema),
461	      warnings: z.array(z.string()),
462	      artifacts: z.array(cliArtifactRefSchema),
463	      startedAt: z.string().min(1),
464	      finishedAt: z.string().min(1),
465	    })
466	    .superRefine((value, ctx) => {
467	      const expectedStatus = statusForOutcome(value.outcome);
468	      if (expectedStatus !== value.status) {
469	        ctx.addIssue({
470	          code: z.ZodIssueCode.custom,
471	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
472	          path: ["status"],
473	        });
474	      }
475	
476	      if (
477	        value.result &&
478	        typeof value.result === "object" &&
479	        "outcome" in value.result &&
480	        typeof value.result.outcome === "string" &&
481	        value.result.outcome !== value.outcome
482	      ) {
483	        ctx.addIssue({
484	          code: z.ZodIssueCode.custom,
485	          message: `Envelope outcome '${value.outcome}' does not match result outcome '${value.result.outcome}'`,
486	          path: ["outcome"],
487	        });
488	      }
489	    });
490	}
