 63	async function resolveRequest(args: {
 64	  "request-file"?: string;
 65	  "request-text"?: string;
 66	}): Promise<string> {
 67	  const requestSources = [
 68	    typeof args["request-file"] === "string" ? "file" : null,
 69	    typeof args["request-text"] === "string" ? "text" : null,
 70	  ].filter(Boolean);
 71	
 72	  if (requestSources.length !== 1) {
 73	    throw new Error("Provide exactly one of --request-file or --request-text.");
 74	  }
 75	
 76	  if (args["request-text"]) {
 77	    const request = args["request-text"].trim();
 78	    if (request.length === 0) {
 79	      throw new Error("--request-text cannot be empty.");
 80	    }
 81	    if (Buffer.byteLength(request, "utf8") > REQUEST_CONTENT_LIMIT_BYTES) {
 82	      throw new Error(
 83	        `--request-text exceeds the 128 KiB limit (${REQUEST_CONTENT_LIMIT_BYTES} bytes).`
 84	      );
 85	    }
 86	    return request;
 87	  }
 88	
 89	  const request = (await readTextFile(resolve(args["request-file"]!))).trim();
 90	  if (request.length === 0) {
 91	    throw new Error("--request-file cannot point to an empty task description.");
 92	  }
 93	  if (Buffer.byteLength(request, "utf8") > REQUEST_CONTENT_LIMIT_BYTES) {
 94	    throw new Error(
 95	      `--request-file exceeds the 128 KiB limit (${REQUEST_CONTENT_LIMIT_BYTES} bytes).`
 96	    );
 97	  }
 98	
 99	  return request;
100	}
