57	export function inspectPromptAssets(): {
58	  basePromptsReady: boolean;
59	  snippetsReady: boolean;
60	  notes: string[];
61	} {
62	  const notes: string[] = [];
63	
64	  for (const assetId of REQUIRED_BASE_PROMPTS) {
65	    if (!EMBEDDED_PROMPT_ASSETS.base[`${assetId}.md`]) {
66	      notes.push(`Missing base prompt asset: ${assetId}.md`);
67	    }
68	  }
69	
70	  for (const assetId of REQUIRED_SNIPPETS) {
71	    if (!EMBEDDED_PROMPT_ASSETS.snippets[`${assetId}.md`]) {
72	      notes.push(`Missing prompt snippet asset: ${assetId}.md`);
73	    }
74	  }
75	
76	  return {
77	    basePromptsReady: notes.every((note) => !note.startsWith("Missing base")),
78	    snippetsReady: notes.every((note) => !note.startsWith("Missing prompt")),
79	    notes,
80	  };
81	}
