 94	/**
 95	 * Extract the first top-level heading from markdown content.
 96	 * Falls back to the filename-derived title if no heading is found.
 97	 */
 98	function extractTitle(content: string, fallback: string): string {
 99	  const match = content.match(/^#\s+(.+)$/m);
100	  return match ? match[1].trim() : fallback;
101	}
102	
103	/**
104	 * Build YAML frontmatter block for a skill.
105	 */
106	function buildFrontmatter(name: string, description: string): string {
107	  return `---\nname: ${name}\ndescription: ${description}\n---`;
108	}
109	
110	/**
111	 * Strip YAML frontmatter from composed content for standalone output.
112	 */
113	function stripFrontmatter(content: string): string {
114	  const fmRegex = /^---\n[\s\S]*?\n---\n*/;
115	  return content.replace(fmRegex, "").trimStart();
116	}
117	
118	async function zipDirectory(
119	  archiveName: string,
120	  directoryName: string,
121	  cwd: string
122	): Promise<void> {
123	  const proc = Bun.spawn(["zip", "-r", archiveName, directoryName], {
124	    cwd,
125	    stdout: "pipe",
126	    stderr: "pipe",
127	  });
128	  const exitCode = await proc.exited;
129	  if (exitCode !== 0) {
130	    const stderr = await new Response(proc.stderr).text();
131	    throw new Error(
132	      `zip failed for ${archiveName} (exit ${exitCode}): ${stderr.trim()}`
133	    );
134	  }
135	}
