137	// ---------------------------------------------------------------------------
138	// Composition
139	// ---------------------------------------------------------------------------
140	
141	async function composeSkill(skill: SkillEntry): Promise<string> {
142	  const parts: string[] = [];
143	
144	  // 1. YAML frontmatter
145	  parts.push(buildFrontmatter(skill.name, skill.description));
146	  parts.push("");
147	
148	  // 2. Phase content
149	  for (const phase of skill.phases) {
150	    const content = await readSourceFile(`phases/${phase}.md`);
151	    parts.push(content.trimEnd());
152	  }
153	
154	  // 3. Shared content
155	  for (const shared of skill.shared) {
156	    const content = await readSourceFile(`shared/${shared}.md`);
157	    const title = extractTitle(content, shared);
158	    parts.push("");
159	    parts.push("---");
160	    parts.push("");
161	    parts.push(`## Reference: ${title}`);
162	    parts.push("");
163	    parts.push(content.trimEnd());
164	  }
165	
166	  // 4. Templates (optional)
167	  if (skill.templates && skill.templates.length > 0) {
168	    for (const template of skill.templates) {
169	      const content = await readSourceFile(`templates/${template}.md`);
170	      parts.push("");
171	      parts.push("---");
172	      parts.push("");
173	      parts.push("## Template");
174	      parts.push("");
175	      parts.push(content.trimEnd());
176	    }
177	  }
178	
179	  // 5. Examples (optional)
180	  if (skill.examples && skill.examples.length > 0) {
181	    for (const example of skill.examples) {
182	      const content = await readSourceFile(`examples/${example}.md`);
183	      parts.push("");
184	      parts.push("---");
185	      parts.push("");
186	      parts.push("## Verification Prompt");
187	      parts.push("");
188	      parts.push(content.trimEnd());
189	    }
190	  }
191	
192	  // Final newline
193	  parts.push("");
194	  return parts.join("\n");
195	}
