 15	async function writeProviderBinary(params: {
 16	  dir: string;
 17	  name: string;
 18	  version: string;
 19	  authStatus?: "authenticated" | "missing";
 20	  authBehavior?: "normal" | "timeout" | "unknown";
 21	  captureCwdPath?: string;
 22	  failureStderr?: string;
 23	  authFailureStderr?: string;
 24	}) {
 25	  const authStatus = params.authStatus ?? "authenticated";
 26	  const scriptPath = join(params.dir, params.name);
 27	  const script = [
 28	    "#!/bin/sh",
 29	    params.captureCwdPath
 30	      ? `printf '%s' \"$PWD\" > "${params.captureCwdPath}"`
 31	      : "",
 32	    'if [ "$1" = "--version" ]; then',
 33	    params.failureStderr
 34	      ? `  echo "${params.failureStderr}" >&2`
 35	      : "",
 36	    `  echo "${params.version}"`,
 37	    "  exit 0",
 38	    "fi",
 39	    'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
 40	    params.authBehavior === "timeout"
 41	      ? "  sleep 2"
 42	      : params.authBehavior === "unknown"
 43	        ? `  echo "${params.authFailureStderr ?? "transient provider failure"}" >&2`
 44	        : authStatus === "authenticated"
 45	          ? '  echo "authenticated"'
 46	          : '  echo "missing" >&2',
 47	    params.authBehavior === "timeout"
 48	      ? "  exit 0"
 49	      : params.authBehavior === "unknown"
 50	        ? "  exit 70"
 51	        : authStatus === "authenticated"
 52	          ? "  exit 0"
 53	          : "  exit 1",
 54	    "fi",
 55	    'echo "unexpected invocation" >&2',
 56	    "exit 1",
 57	    "",
 58	  ].join("\n");
 59	  await writeTextFile(scriptPath, script);
 60	  await chmod(scriptPath, 0o755);
 61	}
